quizDraft.solutionCode:
def calculate_item_total(item):
    return item['price'] * item['quantity']

def print_item(item):
    print(f"{item['name']}: {item['price']} x {item['quantity']}")

def print_receipt(items):
    total = 0
    for item in items:
        total += calculate_item_total(item)
        print_item(item)
    print(f"Total: {total}")

# Example usage
items = [{'name': 'apple', 'price': 1, 'quantity': 3}, {'name': 'banana', 'price': 2, 'quantity': 2}]
print_receipt(items)
